{"file_path":"fastapi-users/app/routes/users.py","new_string":"from fastapi import APIRouter, Depends, HTTPException, status
from sqlalchemy.ext.asyncio import AsyncSession
from app.database import get_db
from app.schemas.user import User, UserCreate, UserUpdate
from app.services.user import create_user, get_user_by_email, update_user, delete_user
from app.deps import get_current_user

router = APIRouter(prefix="/users", tags=["users"])

@router.post("/", response_model=User)
async def create_new_user(
    user: UserCreate,
    db: AsyncSession = Depends(get_db)
):
    db_user = await get_user_by_email(db, email=user.email)
    if db_user:
        raise HTTPException(status_code=400, detail="Email already registered")
    return await create_user(db, user)

@router.get("/me", response_model=User)
async def read_users_me(
    current_user: User = Depends(get_current_user)
):
    return current_user

@router.put("/me", response_model=User)
async def update_users_me(
    user: UserUpdate,
    current_user: User = Depends(get_current_user),
    db: AsyncSession = Depends(get_db)
):
    return await update_user(db, current_user.id, user)

@router.delete("/me", response_model=User)
async def delete_users_me(
    current_user: User = Depends(get_current_user),
    db: AsyncSession = Depends(get_db)
):
    return await delete_user(db, current_user.id)","old_string":""}

