from httpx import AsyncClient

@pytest.mark.asyncio
async def test_create_user(client: AsyncClient):
    user_data = {"email": "test@example.com", "password": "testpassword", "full_name": "Test User"}
    response = await client.post("/users/", json=user_data)

    assert response.status_code == 200
    assert response.json()["email"] == "test@example.com"
    assert response.json()["full_name"] == "Test User"
    assert response.json()["is_active"] == True

@pytest.mark.asyncio
async def test_get_current_user(client: AsyncClient):
    # Create a test user first
    user_data = {"email": "test@example.com", "password": "testpassword", "full_name": "Test User"}
    await client.post("/users/", json=user_data)

    # Login to get token
    login_data = {"username": "test@example.com", "password": "testpassword"}
    login_response = await client.post("/auth/token", data=login_data)
    token = login_response.json()["access_token"]

    # Test get current user
    headers = {"Authorization": f"Bearer {token}"}
    response = await client.get("/users/me", headers=headers)

    assert response.status_code == 200
    assert response.json()["email"] == "test@example.com"

@pytest.mark.asyncio
async def test_update_user(client: AsyncClient):
    # Create a test user first
    user_data = {"email": "test@example.com", "password": "testpassword", "full_name": "Test User"}
    await client.post("/users/", json=user_data)

    # Login to get token
    login_data = {"username": "test@example.com", "password": "testpassword"}
    login_response = await client.post("/auth/token", data=login_data)
    token = login_response.json()["access_token"]

    # Test update user
    update_data = {"full_name": "Updated User"}
    headers = {"Authorization": f"Bearer {token}"}
    response = await client.put("/users/me", json=update_data, headers=headers)

    assert response.status_code == 200
    assert response.json()["full_name"] == "Updated User"

